object Solution { def task_order(deps: Map[String, Any]): Seq[String] = { val adj = scala.collection.mutable.Map[String, scala.collection.mutable.ArrayBuffer[String]](); val indegree = scala.collection.mutable.Map[String, Int]().withDefaultValue(0); def ensure(task: String): Unit = { adj.getOrElseUpdate(task, scala.collection.mutable.ArrayBuffer[String]()); if (!indegree.contains(task)) indegree(task) = 0 }; for ((task, rawPrereqs) <- deps) { ensure(task); for (prereq <- asStringSeq(rawPrereqs)) { ensure(prereq); adj(prereq) += task; indegree(task) += 1 } }; val ready = scala.collection.mutable.ArrayBuffer[String]() ++ indegree.collect { case (task, 0) => task }.toSeq.sorted; val order = scala.collection.mutable.ArrayBuffer[String](); while (ready.nonEmpty) { val task = ready.remove(0); order += task; for (next <- adj(task)) { indegree(next) -= 1; if (indegree(next) == 0) { ready += next; val sorted = ready.sorted; ready.clear(); ready ++= sorted } } }; if (order.length == indegree.size) order.toSeq else null }; private def asStringSeq(value: Any): Seq[String] = value match { case seq: Seq[_] => seq.map(_.toString); case _ => Seq.empty } }
